.tooljet-ai-card-root .ai-icon{width:28px;height:28px;border-radius:7px;background:var(--accent);display:grid;place-items:center;font-size:13px}
.tooljet-ai-card-root .ai-title{font-family:"Bricolage Grotesque",serif;font-size:17px;font-weight:600}
.tooljet-ai-card-root[dir="rtl"] .ai-title{font-family:"Tajawal",serif;font-weight:700}
.tooljet-ai-card-root .ai-status{font-size:10px;color:rgba(255,255,255,.55);text-transform:uppercase;letter-spacing:.06em;margin-top:2px}
.tooljet-ai-card-root[dir="rtl"] .ai-status{text-transform:none;letter-spacing:0}
.tooljet-ai-card-root .ai-insights{display:flex;flex-direction:column;gap:10px;position:relative;z-index:1}
.tooljet-ai-card-root .ai-insight{display:flex;gap:10px;padding:12px 14px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:8px;font-size:13px;line-height:1.55}
.tooljet-ai-card-root .ai-insight-bullet{flex-shrink:0;width:20px;height:20px;border-radius:5px;background:rgba(176,74,46,.25);color:#ffb49c;display:grid;place-items:center;font-size:11px;font-weight:700;margin-top:1px}
.tooljet-ai-card-root .ai-insight-bullet.flag{background:rgba(239,159,47,.25);color:#ffcf8a}
.tooljet-ai-card-root .ai-copy{flex:1}`;

// ---- shared labels ----
const t = {
  status:          isAr ? 'أُنشئت الآن · الذكاء الاصطناعي' : 'Generated just now &middot; AI',
  clusterTitle:    isAr ? 'رؤى على مستوى التجمع'            : 'Cluster-wide Insights',
  aiTitle:         isAr ? 'رؤى الذكاء الاصطناعي'            : 'AI Insights',
  anomalyFlagged:  isAr ? 'شذوذ مُعلَّم:'                    : 'Anomaly flagged:',
  anomaly:         isAr ? 'شذوذ:'                            : 'Anomaly:',
  positive:        isAr ? 'إيجابي:'                          : 'Positive:',
  strong:          isAr ? 'أداء قوي:'                        : 'Strong performance:',
  review:          isAr ? 'مراجعة مطلوبة:'                   : 'Review needed:'
};

// ---- builders ----
const num  = (n, text)       => `<div class="ai-insight"><div class="ai-insight-bullet">${n}</div><div class="ai-copy">${text}</div></div>`;
const flag = (prefix, text)  => `<div class="ai-insight"><div class="ai-insight-bullet flag">!</div><div class="ai-copy"><strong>${prefix}</strong> ${text}</div></div>`;
const panel = (title, body)  => `<style>${css}</style><div class="tooljet-ai-card-root" dir="${dir}"><div class="ai-panel"><div class="ai-head"><div class="ai-icon">&#10022;</div><div><div class="ai-title">${title}</div><div class="ai-status">${t.status}</div></div></div><div class="ai-insights">${body}</div></div></div>`;

// ---- content (EN / AR) ----
const c = isAr ? {
  hub: [
    num(1, 'بلغ متوسط زمن الوصول إلى الطبيب في قسم الطوارئ بمستشفى حائل العام 31 دقيقة هذا الشهر — أعلى من معيار أداء البالغ 25 دقيقة. سعة الفرز هي الاختناق المُرجَّح.'),
    num(2, 'ارتفع إشغال الأسرّة إلى 82.4% على مستوى التجمع (المستهدف 80%). يبلغ مستشفى الملك سلمان التخصصي ذروته عند 94%، مما يرفع مخاطر التجمع.'),
    num(3, 'ارتفع استخدام الرعاية الأولية بنسبة 8% سنويًا عبر 110 مراكز رعاية صحية أولية — برنامج فحص القدم السكرية هو المساهم الأقوى، مما يقلل من الإدخال اللاحق للمستشفى.'),
    flag(t.anomalyFlagged, 'زاد زمن انتظار مواعيد العيادات الخارجية في طب القلب من 18 إلى 34 يومًا خلال الربع الأخير — فجوة سعة الاختصاصيين تستوجب مراجعة عاجلة.')
