    flag(t.strong, 'انخفضت نسبة عدوى موقع الجراحة إلى 1.8% (المستهدف <2.0%) بعد إطلاق برنامج تدقيق قائمة سلامة الجراحة لمنظمة الصحة العالمية في الربع الثالث.')
  ],
  qps: [
    num(1, 'ارتفع رضا المرضى (وصيف) إلى 4.4/5 — الأعلى خلال 24 شهرًا. النظافة والتواصل مع الطاقم حصلا على أعلى الدرجات، وأزمنة الانتظار على الأدنى.'),
    num(2, 'ارتفع الإبلاغ عن أخطاء الأدوية بنسبة 18% — يعكس على الأرجح تحسنًا في ثقافة الإبلاغ، لا زيادة في الأخطاء. تبني سرية هوية المُبلِّغ مرتبط بهذا الاتجاه.'),
    num(3, 'انخفضت نسبة العدوى المرتبطة بالرعاية الصحية 0.6 نقطة مئوية إلى 2.8% — برنامج تدقيق الالتزام بنظافة اليدين (التزام 92%، كان 76%) هو المحرك الرئيسي لهذا التحسن.'),
    flag(t.review, '3 أحداث جسيمة هذا الربع (مقابل 2 في الربع الماضي). تحليل السبب الجذري جارٍ لكل منها؛ لم يتم تحديد خيط مشترك بعد ولكنها تستدعي متابعة دقيقة.')
