} : {
  hub: [
    num(1, "ED door-to-doctor time at Hail General Hospital averaged 31 minutes this month &mdash; above the Ada'a 25-minute benchmark. Triage capacity is the likely bottleneck."),
    num(2, 'Bed occupancy rose to 82.4% cluster-wide (target 80%). King Salman Specialist Hospital is peaking at 94%, driving cluster risk.'),
    num(3, 'Primary care utilization up 8% YoY across 110 PHC centers &mdash; diabetic foot screening program is the strongest contributor, reducing downstream hospitalization.'),
    flag(t.anomalyFlagged, 'OPD appointment waiting time in Cardiology increased from 18 to 34 days over the last quarter &mdash; specialist capacity gap requires urgent review.')
  ],
  ed: [
    num(1, 'Door-to-Doctor time spiked from 25 to 35 minutes in weeks 6-8, correlating with a 22% surge in non-urgent (CTAS 5) visits. Triage bottleneck identified.'),
    num(2, "Hail General Hospital's ED is underperforming vs the Ada'a 4-hour disposition target (71%) while Moqaq General is meeting it (89%). Staffing mix differs significantly."),
