// ---- return same shape as before ----
return {
  hub_dashboard:          { html: panel(t.clusterTitle, c.hub.join('')) },
  emergency_services:     { html: panel(t.aiTitle,      c.ed.join(''))  },
  inpatient_services:     { html: panel(t.aiTitle,      c.ip.join(''))  },
  primary_care_opd:       { html: panel(t.aiTitle,      c.opd.join('')) },
  surgical_services:      { html: panel(t.aiTitle,      c.surg.join('')) },
  quality_patient_safety: { html: panel(t.aiTitle,      c.qps.join(''))  }
};

const labels = {
  'executive-hub':          { en: 'Executive Hub',          ar: 'المركز التنفيذي' },
  'emergency-services':     { en: 'Emergency Services',     ar: 'خدمات الطوارئ' },
  'inpatient-services':     { en: 'Inpatient Services',     ar: 'خدمات المرضى الداخليين' },
  'surgical-services':      { en: 'Surgical Services',      ar: 'الخدمات الجراحية' },
  'primary-care-opd':       { en: 'Primary Care & OPD',     ar: 'الرعاية الأولية والعيادات الخارجية' },
  'quality-patient-safety': { en: 'Quality & Patient Safety', ar: 'الجودة وسلامة المرضى' },
};

const lang = variables.language === 'ar' ? 'ar' : 'en';

const apply = () => {
  Object.entries(labels).forEach(([slug, t]) => {
    const textEl = document.querySelector(`[data-cy="pages-name-${slug}"] .page-name`);
    if (textEl) textEl.textContent = t[lang];

    // keep aria-label in sync for a11y
    const btn = textEl?.closest('button');
    if (btn) btn.setAttribute('aria-label', t[lang]);
  });
};

apply();

// Safety net: nav re-renders on page switch, so re-apply after a tick
setTimeout(apply, 100);
setTimeout(apply, 400);
return 'ok';
